module top_module(A, B, Ci, S, Co);input A, B, Ci;
  output S, Co;
  wire   n1, n2, n3, n4, n5;

  // XOR gates for sum
  assign Co = n2 | n3 | n4;
  assign n4 = B & Ci;

  // AND gates for carry-out
  assign n3 = A & Ci;
  assign n2 = A & B;
  assign S = n1 ^ Ci;

  // OR gate for carry-out
  assign n1 = A ^ B;
endmodule
